var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 저도 그냥 신분증 하나 사서 고향으로 내려갈까 봐요.","JPN":"おばさん、私も身分証を買って故郷に帰っちゃいますかね。","ENG":"Madam, I think I’ll go buy an ID card and go down to my hometown.","TWN":"伯母，我可能會買個身分證回老家去。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……? 손님……. 집으로 가려고……?","JPN":"ん……？　お客さん……家に帰るつもり……？","ENG":"Huh...? Are you... going home...?","TWN":"嗯……？客人……你要回家喔……？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아가 좋아하는 것 같던데……. 조금만 더 있다 가지…….","JPN":"レアが気に入ってたのに……もう少しゆっくりして行ったら……","ENG":"But Leah seems to like you... Stay just a little longer...","TWN":"我們蕾亞好像很喜歡你……你再多待幾天嘛……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그건 그냥 찌그러진 레서판다 보고 귀여워하는 느낌이라고 생각하는데요.","JPN":"それはただぺちゃんこになったレッサーパンダーを見てかわいがっている感じだと思いますよ。","ENG":"Likes me? I think it’s more like she sees me as this cute red panda that’s nice to have around.","TWN":"她只是覺得小貓熊很可愛吧？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……레서판다가 어떻게 생긴 동물인지는 잘 모르지만요.","JPN":"……レッサーパンダーがどんな動物かはよくわかりませんが。","ENG":"...Though to be honest I’m not even really sure what a red panda looks like.","TWN":"……雖然我也不知道小貓熊長什麼樣。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"후후……. 생긴 것도 하는 것도 아주 깜찍한 동물이지…….","JPN":"ふふ……見かけも、やることもとってもかわいらしい動物ね……","ENG":"Ha ha... It’s an animal that looks cute and acts cute...","TWN":"呵呵……小貓熊的長相和動作都很可愛喔……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 그렇다면 다행이네요.","JPN":"へえ……それはよかったですね。","ENG":"Huh. That’s good then, I guess.","TWN":"喔……那還好。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사실 어릴 때 입 삐죽거린다고 오리 너구리란 소리도 들었거든요.","JPN":"実は小さい頃、口を尖らせるからカモノハシって言われたこともあったんです。","ENG":"When I was little, I heard I looked like the ugly duckling whenever I pouted.","TWN":"我小時候常扁嘴，還有人說我是鴨嘴獸呢。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"브레히트 중사님.","JPN":"ブレヒト軍曹。","ENG":"Sergeant Brecht.","TWN":"布萊希特中士，"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 본 기로 접근 중인 인물이 포착되었습니다. 무장한 상태예요.","JPN":"現在、本機に接近している人物が確認されました。武装状態です。","ENG":"I’ve detected someone approaching this ship. They are armed.","TWN":"發現有武裝份子正在接近本機。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그러면 허탕 치라고 부리나케 도망쳐야죠.","JPN":"だったら、肩透かしを食らわすためにも急いで逃げないとね。","ENG":"Well, then clearly we should make like a tree and get out of here now.","TWN":"那應該三十六計走為上策吧！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 잠깐 실례할게요.","JPN":"おばさん、ちょっと失礼します。","ENG":"Excuse me for a moment, Madam.","TWN":"伯母，失禮囉！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아윽?!","JPN":"あうっ！？","ENG":"Ugh!","TWN":"呃？！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"소, 손님……!","JPN":"お、お客さん……！","ENG":"A-are you..!","TWN":"客…客人……！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"함교에 침입자 감지!","JPN":"艦橋に侵入者を感知！","ENG":"Detecting an intruder on the bridge!","TWN":"有人入侵艦橋！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};